shape.script:
function getHandles(params) {
    let stemSize = params.stemSize;
    return {
        ss: [stemSize/2, stemSize/2],
        n: [0, -params.size.y],
        s: [0, params.size.y],
        e: [params.size.x, 0],
        w: [-params.size.x, 0],
        ne: [params.size.x, -params.size.y],
        se: [params.size.x, params.size.y],
        nw: [-params.size.x, -params.size.y],
        sw: [-params.size.x, params.size.y]
    }
}

function getPath(params) {
    let width = params.size.x;
    let height = params.size.y;
    let stemSize = params.stemSize;
    return [
        [-stemSize/2,-height],
        [stemSize/2,-height],
        [stemSize/2,-stemSize/2],
        [width,-stemSize/2],
        [width,stemSize/2],
        [stemSize/2,stemSize/2],
        [stemSize/2,height],
        [-stemSize/2,height],
        [-stemSize/2,stemSize/2],
        [-width,stemSize/2],
        [-width,-stemSize/2],
        [-stemSize/2,-stemSize/2],
        {closed:true}
    ];
}
